1	import * as React from "react";
2	import Link from "next/link";
3	import { notFound } from "next/navigation";
4	import {
5	  ArrowLeft,
6	  FileWarning,
7	  ArrowRight,
8	  Check,
9	  AlertTriangle,
10	  Mail,
11	  Pencil,
12	  XCircle,
13	  Wallet,
14	  TrendingUp,
15	} from "lucide-react";
16	import { getShowById } from "@/lib/queries";
17	import {
18	  Card,
19	  CardContent,
20	  CardHeader,
21	  CardTitle,
22	  CardDescription,
23	  Field,
24	} from "@/components/ui/card";
25	import { StatusBadge, DealTypeBadge, PlainBadge } from "@/components/ui/badge";
26	import { calculateSettlement } from "@/lib/dealMath";
27	import {
28	  formatMoney,
29	  formatShowDateFull,
30	} from "@/lib/format";
31	import type { Settlement, Recoup } from "@/db/schema";
32	import { Logomark } from "@/components/brand/logo";
33	
34	const RECOUP_LABELS: Record<Recoup["category"], string> = {
35	  marketing: "Marketing",
36	  hospitality_overage: "Hospitality overage",
37	  production_overage: "Production overage",
38	  prior_advance: "Prior advance",
39	  backline: "Backline",
40	  damages: "Damages",
41	  other: "Other",
42	};
43	
44	export default async function SettlePage({
45	  params,
46	}: {
47	  params: Promise<{ id: string }>;
48	}) {
49	  const { id } = await params;
50	  const data = await getShowById(id);
51	  if (!data) notFound();
52	
53	  const { show, artist, deal, ticketSales, expenses, settlement, recoups } =
54	    data;
55	
56	  if (!deal) {
57	    return (
58	      <div className="px-12 py-10 max-w-4xl">
59	        <BackLink showId={show.id} />
60	        <div className="text-[13px] text-ink-400">
61	          No deal entered for this show. Settlement can&apos;t run yet.
62	        </div>
63	      </div>
64	    );
65	  }
66	
67	  const calc = calculateSettlement({
68	    deal,
69	    ticketSales,
70	    expenses,
71	    comps: data.comps,
72	    recoupApplications: recoups,
73	    venueCapacity: data.venue?.capacity ?? undefined,
74	  });
75	  const grossSoFar = ticketSales.reduce((sum, t) => sum + t.gross, 0);
76	  const totalFees = ticketSales.reduce((sum, t) => sum + t.fees, 0);
77	  const totalExpenses = expenses
78	    .filter((e) => !e.absorbedByVenue)
79	    .reduce((sum, e) => sum + e.amount, 0);
80	
81	  const disputedRecoups = recoups.filter((r) => r.status === "disputed");
82	  const isDisputed = settlement?.status === "disputed" || settlement?.status === "revised" || !!settlement?.disputedAt;
83	  const disputedRecoupValue = disputedRecoups.reduce((s, r) => s + r.amount, 0);
84	
85	  return (
86	    <div className={`px-12 py-10 max-w-7xl ${isDisputed ? "bg-gradient-to-b from-rose-50/30 via-canvas to-canvas" : ""}`}>
87	      <BackLink showId={show.id} />
88	
89	      <div className="mb-20">
90	        <div className="flex items-center gap-1.5 mb-4">
91	          <StatusBadge status={show.status} />
92	          <DealTypeBadge type={deal.dealType} />
93	          {settlement?.status === "disputed" && (
94	            <span className="inline-flex items-center gap-1.5 px-2 py-0.5 rounded-md text-[10.5px] font-medium ring-1 ring-inset bg-rose-50 text-rose-800 ring-rose-200/80">
95	              <span className="relative flex h-1.5 w-1.5">
96	                <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-rose-400 opacity-75" />
97	                <span className="relative inline-flex rounded-full h-1.5 w-1.5 bg-rose-500" />
98	              </span>
99	              Disputed
100	            </span>
101	          )}
102	          {settlement?.status === "voided" && (
103	            <PlainBadge variant="default">Voided</PlainBadge>
104	          )}
105	        </div>
106	        <h1 className="font-display text-[48px] font-medium text-ink-900 leading-[1.05]" style={{ letterSpacing: "-0.02em", fontOpticalSizing: "auto" }}>
107	          Settlement · {artist?.name}
108	        </h1>
109	        <div className="text-[14px] text-ink-400 mt-3">
110	          {formatShowDateFull(show.date)}
111	        </div>
112	      </div>
113	
114	      {/* Disputed callout */}
115	      {isDisputed && disputedRecoupValue > 0 && (
116	        <div className="mb-8 rounded-lg border border-rose-200/60 bg-rose-50/40 p-5 flex gap-3">
117	          <AlertTriangle className="h-4 w-4 text-rose-700 mt-0.5 shrink-0" />
118	          <div>
119	            <div className="text-[13px] font-semibold text-rose-800">
120	              {disputedRecoups.length} recoup{disputedRecoups.length === 1 ? "" : "s"} in dispute · {formatMoney(disputedRecoupValue)} contested
121	            </div>
122	            <p className="text-[12.5px] text-ink-600 mt-1 leading-relaxed">
123	              The artist team has flagged recoup line items. This settlement cannot be finalized until the dispute is resolved.
124	            </p>
125	          </div>
126	        </div>
127	      )}
128	
129	      {settlement && (
130	        <LifecycleBar settlement={settlement} disputedRecoups={disputedRecoups.length} />
131	      )}
132	
133	      <div className="space-y-6 mt-6">
134	        {!calc.supported ? (
135	          <UnsupportedDeal
136	            dealType={calc.dealType}
137	            kind={calc.kind}
138	            reason={calc.reason}
139	            deal={deal}
140	            existingSettlement={settlement}
141	            grossSoFar={grossSoFar}
142	            totalFees={totalFees}
143	            totalExpenses={totalExpenses}
144	            ticketCount={ticketSales.reduce((s, t) => s + (t.qty ?? 0), 0)}
145	            expenseRowCount={expenses.length}
146	          />
147	        ) : (
148	          <SupportedSettlement calc={calc} existingSettlement={settlement} />
149	        )}
150	
151	        {recoups.length > 0 && <RecoupsSection recoups={recoups} />}
152	
153	        {settlement && (settlement.signoffText || settlement.notes) && (
154	          <SignoffSection settlement={settlement} />
155	        )}
156	      </div>
157	
158	      <div className="mt-16 pt-10 border-t border-ink-200/60">
159	        <div className="flex gap-4 items-start max-w-3xl">
160	          <Logomark size={40} className="shrink-0" />
161	          <div>
162	            <h2 className="font-display text-[20px] font-medium text-ink-900 mb-2" style={{ letterSpacing: "-0.02em" }}>
163	              You&apos;re looking at the seam this case study is about.
164	            </h2>
165	            <p className="text-[13px] text-ink-500 leading-relaxed">
166	              Greenroom&apos;s in-app settlement tool was built early in the
167	              company&apos;s history, when most deals were flat guarantees.
168	              About 18% of customers actively use it; the other 82% — including
169	              most of the larger venues — default to spreadsheets. The CEO has
170	              flagged this as the company&apos;s biggest craft gap.{" "}
171	              <Link
172	                href="/context"
173	                className="text-brand-700 font-medium hover:text-brand-800 hover:underline inline-flex items-center gap-0.5"
174	              >
175	                Where to start <ArrowRight className="h-3 w-3" />
176	              </Link>
177	            </p>
178	          </div>
179	        </div>
180	      </div>
181	    </div>
182	  );
183	}
184	
185	function BackLink({ showId }: { showId: string }) {
186	  return (
187	    <Link
188	      href={`/shows/${showId}`}
189	      className="inline-flex items-center gap-1 text-[12px] text-ink-400 hover:text-ink-900 mb-8 transition-colors"
190	    >
191	      <ArrowLeft className="h-3.5 w-3.5" /> Back to show
192	    </Link>
193	  );
194	}
195	
196	type Stage = {
197	  key: string;
198	  label: string;
199	  icon: React.ComponentType<{ className?: string }>;
200	  timestamp?: Date | null;
201	};
202	
203	function LifecycleBar({
204	  settlement,
205	  disputedRecoups,
206	}: {
207	  settlement: Settlement;
208	  disputedRecoups: number;
209	}) {
210	  if (settlement.status === "voided") {
211	    return (
212	      <div className="rounded-lg border border-ink-200/80 bg-white px-5 py-4 flex items-center gap-3">
213	        <XCircle className="h-4 w-4 text-ink-400" />
214	        <div>
215	          <div className="text-[13px] font-medium text-ink-900">
216	            Settlement voided
217	          </div>
218	          <div className="text-[11.5px] text-ink-400 mt-0.5">
219	            The show was cancelled or the settlement was scrapped.
220	          </div>
221	        </div>
222	      </div>
223	    );
224	  }
225	
226	  const stages: Stage[] = [
227	    {
228	      key: "draft",
229	      label: "Drafted",
230	      icon: Pencil,
231	      timestamp: settlement.draftedAt,
232	    },
233	    {
234	      key: "submitted",
235	      label: "Submitted",
236	      icon: Mail,
237	      timestamp: settlement.submittedAt,
238	    },
239	    {
240	      key: "review",
241	      label: "Reviewed",
242	      icon: TrendingUp,
243	      timestamp: settlement.reviewStartedAt,
244	    },
245	    {
246	      key: "signed",
247	      label: settlement.disputedAt ? "Finalized" : "Signed",
248	      icon: Check,
249	      timestamp: settlement.finalizedAt ?? settlement.signedAt,
250	    },
251	    {
252	      key: "paid",
253	      label: "Paid",
254	      icon: Wallet,
255	      timestamp: settlement.paidAt,
256	    },
257	  ];
258	
259	  const currentIndex = (() => {
260	    switch (settlement.status) {
261	      case "draft":
262	        return 0;
263	      case "submitted":
264	        return 1;
265	      case "in_review":
266	        return 2;
267	      case "disputed":
268	      case "signed":
269	      case "revised":
270	      case "finalized":
271	        return 3;
272	      case "paid":
273	        return 4;
274	      default:
275	        return 0;
276	    }
277	  })();
278	
279	  const isDisputed =
280	    settlement.status === "disputed" ||
281	    settlement.status === "revised" ||
282	    !!settlement.disputedAt;
283	
284	  return (
285	    <Card>
286	      <CardContent className="py-5">
287	        <div className="flex items-center justify-between mb-4">
288	          <div className="eyebrow text-[10px] text-ink-400">
289	            Settlement lifecycle
290	          </div>
291	          {isDisputed && (
292	            <div className="flex items-center gap-1.5 text-[11px] font-medium text-rose-700">
293	              <AlertTriangle className="h-3 w-3" />
294	              {settlement.status === "disputed"
295	                ? "In dispute"
296	                : settlement.status === "revised"
297	                  ? "Revision sent"
298	                  : "Resolved after dispute"}
299	              {disputedRecoups > 0 && (
300	                <span className="text-rose-600">
301	                  · {disputedRecoups} disputed recoup
302	                  {disputedRecoups === 1 ? "" : "s"}
303	                </span>
304	              )}
305	            </div>
306	          )}
307	        </div>
308	
309	        <div className="grid grid-cols-5 gap-1 relative">
310	          <div className="absolute top-3.5 left-[10%] right-[10%] h-px bg-ink-200/60" />
311	
312	          {stages.map((stage, i) => {
313	            const isComplete = i < currentIndex;
314	            const isCurrent = i === currentIndex;
315	            const isFuture = i > currentIndex;
316	            const Icon = stage.icon;
317	
318	            const stageDot = (() => {
319	              if (isComplete) {
320	                return "bg-brand-700 ring-brand-700 text-white";
321	              }
322	              if (isCurrent) {
323	                return isDisputed
324	                  ? "bg-rose-50 ring-rose-500 text-rose-700"
325	                  : "bg-brand-50 ring-brand-700 text-brand-700";
326	              }
327	              return "bg-white ring-ink-200/80 text-ink-300";
328	            })();
329	
330	            return (
331	              <div
332	                key={stage.key}
333	                className="flex flex-col items-center text-center"
334	              >
335	                <div
336	                  className={`relative z-10 w-7 h-7 rounded-full ring-2 flex items-center justify-center ${stageDot}`}
337	                >
338	                  <Icon className="h-3.5 w-3.5" />
339	                </div>
340	                <div
341	                  className={`mt-2.5 text-[11px] font-medium leading-tight ${
342	                    isFuture ? "text-ink-300" : "text-ink-900"
343	                  }`}
344	                >
345	                  {stage.label}
346	                </div>
347	                <div className="text-[10px] text-ink-400 mt-0.5 font-mono tabular leading-tight min-h-[12px]">
348	                  {stage.timestamp
349	                    ? new Date(stage.timestamp).toLocaleDateString("en-US", {
350	                        month: "short",
351	                        day: "numeric",
352	                      })
353	                    : ""}
354	                </div>
355	              </div>
356	            );
357	          })}
358	        </div>
359	      </CardContent>
360	    </Card>
361	  );
362	}
363	
364	function UnsupportedDeal({
365	  dealType,
366	  kind,
367	  reason,
368	  deal,
369	  existingSettlement,
370	  grossSoFar,
371	  totalFees,
372	  totalExpenses,
373	  ticketCount,
374	  expenseRowCount,
375	}: {
376	  dealType: string;
377	  kind: "deal_type_unsupported" | "deal_misconfigured";
378	  reason: string;
379	  deal: NonNullable<Awaited<ReturnType<typeof getShowById>>>["deal"];
380	  existingSettlement: NonNullable<
381	    Awaited<ReturnType<typeof getShowById>>
382	  >["settlement"];
383	  grossSoFar: number;
384	  totalFees: number;
385	  totalExpenses: number;
386	  ticketCount: number;
387	  expenseRowCount: number;
388	}) {
389	  const friendly: Record<string, string> = {
390	    flat: "flat guarantee",
391	    percentage_of_gross: "percentage of gross",
392	    percentage_of_net: "percentage of net",
393	    vs: "vs deal",
394	    door: "door deal",
395	  };
396	
397	  return (
398	    <>
399	      <Card accent={kind === "deal_misconfigured" ? "rose" : "amber"}>
400	        <CardContent className="py-12 text-center">
401	          <div className={`inline-flex h-12 w-12 items-center justify-center rounded-full ring-1 mb-5 ${
402	            kind === "deal_misconfigured"
403	              ? "bg-rose-50 ring-rose-200/80"
404	              : "bg-amber-50 ring-amber-200/80"
405	          }`}>
406	            <FileWarning className={`h-5 w-5 ${
407	              kind === "deal_misconfigured" ? "text-rose-700" : "text-amber-700"
408	            }`} />
409	          </div>
410	          <h2 className="font-display text-[22px] font-medium text-ink-900 mb-2" style={{ letterSpacing: "-0.02em" }}>
411	            {kind === "deal_misconfigured"
412	              ? "This deal needs cleanup before settlement can run."
413	              : `The in-app tool can't settle a ${friendly[dealType] ?? dealType} yet.`}
414	          </h2>
415	          <p className="text-[13px] text-ink-500 max-w-md mx-auto leading-relaxed">
416	            {reason}
417	          </p>
418	        </CardContent>
419	      </Card>
420	
421	      <Card>
422	        <CardHeader>
423	          <div>
424	            <CardTitle>What the system has</CardTitle>
425	            <CardDescription>
426	              The inputs Mariana would pull together to settle this show.
427	              They&apos;re here — but disconnected from the deal terms.
428	            </CardDescription>
429	          </div>
430	        </CardHeader>
431	        <CardContent>
432	          <div className="grid grid-cols-1 sm:grid-cols-3 gap-5">
433	            <Field
434	              label="Gross box office"
435	              mono
436	              value={formatMoney(grossSoFar)}
437	            />
438	            <Field label="Fees" mono value={formatMoney(totalFees)} />
439	            <Field
440	              label="Net box office"
441	              mono
442	              value={formatMoney(grossSoFar - totalFees)}
443	            />
444	          </div>
445	
446	          <div className="mt-6 grid grid-cols-1 sm:grid-cols-3 gap-5">
447	            <Field label="Tickets sold" mono value={String(ticketCount)} />
448	            <Field
449	              label="Expenses (line items)"
450	              mono
451	              value={String(expenseRowCount)}
452	            />
453	            <Field
454	              label="Expenses (passed through)"
455	              mono
456	              value={formatMoney(totalExpenses)}
457	            />
458	          </div>
459	
460	          {deal?.dealNotesFreetext && (
461	            <div className="mt-6">
462	              <div className="eyebrow text-[10px] text-ink-500 mb-2">
463	                Deal notes (free text — what Mariana actually trusts)
464	              </div>
465	              <div className="text-[12.5px] text-ink-800 bg-canvas-soft rounded-lg p-4 ring-1 ring-ink-200/60 leading-relaxed">
466	                {deal.dealNotesFreetext}
467	              </div>
468	            </div>
469	          )}
470	        </CardContent>
471	      </Card>
472	
473	      {existingSettlement?.totalToArtist != null && (
474	        <Card
475	          accent={existingSettlement.status === "disputed" ? "rose" : "brand"}
476	        >
477	          <CardHeader>
478	            <div>
479	              <CardTitle>Actually settled (off-platform)</CardTitle>
480	              <CardDescription>
481	                Mariana ran this in a spreadsheet. Here&apos;s the result that
482	                was logged back into Greenroom afterward.
483	              </CardDescription>
484	            </div>
485	            {existingSettlement.status === "disputed" ? (
486	              <PlainBadge variant="rose">Disputed</PlainBadge>
487	            ) : (
488	              <PlainBadge variant="brand">Signed</PlainBadge>
489	            )}
490	          </CardHeader>
491	          <CardContent>
492	            <div className="flex items-baseline justify-between py-2">
493	              <span className="text-[13px] text-ink-600">Total to artist</span>
494	              <span className="text-[32px] font-mono tabular font-semibold text-ink-900" style={{ letterSpacing: "-0.02em" }}>
495	                {formatMoney(existingSettlement.totalToArtist)}
496	              </span>
497	            </div>
498	          </CardContent>
499	        </Card>
500	      )}
501	    </>
502	  );
503	}
504	
505	function SupportedSettlement({
506	  calc,
507	  existingSettlement,
508	}: {
509	  calc: Extract<
510	    ReturnType<typeof calculateSettlement>,
511	    { supported: true }
512	  >;
513	  existingSettlement: NonNullable<
514	    Awaited<ReturnType<typeof getShowById>>
515	  >["settlement"];
516	}) {
517	  return (
518	    <>
519	      {/* Hero number */}
520	      <div className="text-center py-10 mb-2">
521	        <div className="eyebrow text-[10px] text-ink-400 mb-3">Total to artist</div>
522	        <div
523	          className="text-[72px] font-mono tabular font-bold text-ink-900 leading-none"
524	          style={{ letterSpacing: "-0.03em" }}
525	        >
526	          {formatMoney(calc.totalToArtist)}
527	        </div>
528	        {existingSettlement && (
529	          <div className="mt-3">
530	            {existingSettlement.status === "paid" ? (
531	              <PlainBadge variant="brand">Paid</PlainBadge>
532	            ) : existingSettlement.status === "signed" ||
533	              existingSettlement.status === "finalized" ? (
534	              <PlainBadge variant="brand">Signed</PlainBadge>
535	            ) : existingSettlement.status === "disputed" ? (
536	              <PlainBadge variant="rose">Disputed</PlainBadge>
537	            ) : null}
538	          </div>
539	        )}
540	        {existingSettlement?.totalToArtist != null &&
541	          existingSettlement.totalToArtist !== calc.totalToArtist && (
542	          <div className="text-[12px] text-ink-400 mt-2">
543	            Originally settled at{" "}
544	            <span className="font-mono tabular text-ink-600">
545	              {formatMoney(existingSettlement.totalToArtist)}
546	            </span>
547	          </div>
548	        )}
549	      </div>
550	
551	      {/* Box-office facts */}
552	      <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
553	        <StatCard
554	          label="Gross box office"
555	          value={formatMoney(calc.grossBoxOffice)}
556	        />
557	        <StatCard
558	          label="Net box office"
559	          value={formatMoney(calc.netBoxOffice)}
560	        />
561	        <StatCard
562	          label="Total expenses (passed through)"
563	          value={formatMoney(calc.totalExpenses)}
564	        />
565	      </div>
566	
567	      {/* Worksheet breakdown */}
568	      <Card accent="brand">
569	        <CardHeader>
570	          <div>
571	            <CardTitle>Settlement worksheet</CardTitle>
572	          </div>
573	        </CardHeader>
574	        <CardContent>
575	          <div className="divide-y divide-ink-100/80">
576	            {(() => {
577	              const firstPercentageIdx = calc.steps.findIndex(
578	                (s) => s.side === "percentage",
579	              );
580	              const hasGuaranteeBefore =
581	                firstPercentageIdx > 0 &&
582	                calc.steps
583	                  .slice(0, firstPercentageIdx)
584	                  .some((s) => s.side === "guarantee");
585	              return calc.steps.map((step, i) => (
586	                <React.Fragment key={i}>
587	                  {i === firstPercentageIdx && hasGuaranteeBefore && (
588	                    <VsDivider />
589	                  )}
590	                  <Row
591	                    label={step.label}
592	                    value={formatMoney(step.value)}
593	                    note={step.note}
594	                    kind={step.kind}
595	                  />
596	                </React.Fragment>
597	              ));
598	            })()}
599	          </div>
600	          <div className="mt-3 flex items-baseline justify-between py-3 font-semibold border-t border-ink-100/80">
601	            <span className="text-[13px] text-ink-900">Total to artist</span>
602	            <span className="text-[18px] font-mono tabular text-ink-900">
603	              {formatMoney(calc.totalToArtist)}
604	            </span>
605	          </div>
606	        </CardContent>
607	      </Card>
608	
609	      {calc.comparison && <VsComparison comparison={calc.comparison} />}
610	
611	      {calc.bonusesNotTriggered.length > 0 && (
612	        <Card>
613	          <CardHeader>
614	            <CardTitle>Bonuses not triggered</CardTitle>
615	            <CardDescription>
616	              Structured bonuses on this deal that didn&apos;t hit. Shown for
617	              transparency — useful when the agent asks &quot;what about that
618	              gross threshold bonus?&quot;
619	            </CardDescription>
620	          </CardHeader>
621	          <CardContent className="divide-y divide-ink-100/80">
622	            {calc.bonusesNotTriggered.map((b, i) => (
623	              <div
624	                key={i}
625	                className="py-3 flex items-baseline justify-between gap-4"
626	              >
627	                <div className="min-w-0">
628	                  <div className="text-[13px] text-ink-600">{b.label}</div>
629	                  <div className="text-[11.5px] text-ink-400 mt-0.5">
630	                    {b.reason}
631	                  </div>
632	                </div>
